create_page(){
  path="$1"
  title="$2"
  body="$3"
  mkdir -p "dist$path"
  cat > "dist$path/index.html" <<HTML
<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8" />
<meta name="viewport" content="width=device-width, initial-scale=1" />
<title>$title</title>
<link rel="icon" type="image/svg+xml" href="/favicon.svg" />
<link rel="stylesheet" href="/styles.css" />
</head>
<body>
$header_markup
$body
$footer_markup
</body>
</html>
HTML
}

create_page "/" "Future Contractors of America | FCA Contractor Command" '
<main>
  <section class="hero hero-tight">
    <div class="wrap hero-grid">
      <div>
        <div class="kicker"><b>Flagship product</b> FCA Contractor Command</div>
        <h1>Close more work with a contractor operating system that keeps sales, proposals, and handoff moving in one direction.</h1>
        <p class="lead">FCA Contractor Command is positioned for contractors who need a cleaner front-end revenue path: stronger intake, clearer bid continuity, better proposal follow-through, and a guided transition into job setup with Auricrux as the operating intelligence layer.</p>
        <div class="cta-row">
          <a class="btn btn-primary" href="/pricing/">View Pricing</a>
          <a class="btn btn-secondary" href="/intake/">Start Intake</a>
          <a class="btn btn-secondary" href="/auricrux/">Meet Auricrux</a>
        </div>
        <div class="signals"><span class="signal">Marketing-only homepage</span><span class="signal">Lead-to-award story</span><span class="signal">Auricrux command layer</span><span class="signal">Front-facing activation path</span></div>
        <div class="logo-strip">
          <div class="logo-mark"><img src="/favicon.svg" alt="FCA logo" style="width:42px;height:42px" /><div><strong>FCA</strong><div class="small">Future Contractors of America</div></div></div>
          <div class="logo-mark auricrux-mark"><div style="width:42px;height:42px;border-radius:12px;background:linear-gradient(135deg,#7C5313 0%,#D49A22 100%);display:flex;align-items:center;justify-content:center;font-weight:900;color:#fff">A</div><div><strong class="gold">Auricrux</strong><div class="small">Executive command layer</div></div></div>
        </div>
      </div>
      <aside class="card">
        <h2>What a buyer should understand in under a minute</h2>
        <div class="list">
          <div class="row"><span class="dot"></span><div><strong>FCA helps win and convert work</strong><p>FCA is sold as a cleaner commercial system for intake, bids, proposals, and sales-to-operations handoff.</p></div></div>
          <div class="row"><span class="dot"></span><div><strong>Auricrux is part of the product</strong><p>Auricrux is presented as the gold-branded intelligence layer that helps buyers understand fit, value, and next steps.</p></div></div>
          <div class="row"><span class="dot"></span><div><strong>Clear commercial path</strong><p>Pricing, intake, activation, and login are separated cleanly so the public site reads like a real product funnel.</p></div></div>
        </div>
      </aside>
    </div>
  </section>
  <section class="section"><div class="wrap"><h2>FCA sells continuity where other contractor tools create friction</h2><p>Instead of sending a buyer from form to spreadsheet to email to disconnected quote workflow, FCA positions the contractor journey as one coordinated system: lead intake, qualification, bid movement, proposal positioning, award visibility, and the first setup path into the job.</p><div class="grid-3"><article class="card"><h3>Sales and intake</h3><p>Capture the right buyer information up front and move it into a structured commercial path instead of restarting the conversation later.</p></article><article class="card"><h3>Proposal and award</h3><p>Make the offer clearer, reduce dropped context, and keep the outcome attached to what comes next.</p></article><article class="card"><h3>Auricrux command layer</h3><p>Give prospects and customers a visible intelligence layer that can explain value, compare packages, and point to the next commercial action.</p></article></div></div></section>
  <section class="section"><div class="wrap"><h2>Flagship workflow spine</h2><div class="grid-4"><div class="stage"><small>01</small><strong>Lead + Intake</strong><p>Capture company, scope, urgency, and commercial intent.</p></div><div class="stage"><small>02</small><strong>Estimate + Bid</strong><p>Carry the opportunity into pricing, scope control, and bid posture.</p></div><div class="stage"><small>03</small><strong>Proposal + Award</strong><p>Present the offer and keep the outcome connected to the next stage.</p></div><div class="stage"><small>04</small><strong>Job Setup</strong><p>Turn won work into the first true operational record.</p></div></div></div></section>
</main>'

create_page "/features" "FCA Features" '
<main class="hero-simple"><div class="wrap"><div class="kicker"><b>Product</b> Features</div><h1>Features designed to make contractor revenue flow cleaner.</h1><p class="lead">FCA Contractor Command is marketed around the outcomes a buyer can understand quickly: better intake, stronger bid continuity, clearer proposal handling, and a more guided transition into real delivery work.</p><div class="grid-3 section"><article class="card"><h3>Guided intake</h3><p>Front-facing intake helps contractors gather the right commercial and scope details earlier.</p></article><article class="card"><h3>Bid continuity</h3><p>FCA keeps the opportunity moving without dropped context between intake, estimate, and proposal posture.</p></article><article class="card"><h3>Proposal support</h3><p>Give buyers a clearer path from pricing and scope into proposal and award movement.</p></article><article class="card"><h3>Customer coordination</h3><p>Position the customer journey as connected and professional from the first interaction forward.</p></article><article class="card"><h3>Academy alignment</h3><p>Keep workforce readiness and system adoption part of the same platform story.</p></article><article class="card"><h3>Auricrux guidance</h3><p>Use Auricrux to explain the offer, compare fit, and direct the next step.</p></article></div></div></main>'

create_page "/solutions" "FCA Solutions" '
<main class="hero-simple"><div class="wrap"><div class="kicker"><b>Product</b> Solutions</div><h1>Solutions for contractors who want one commercial system instead of disconnected front-end tools.</h1><p class="lead">FCA is positioned for contractors who want a smoother sales path, cleaner bid handling, and better transition from customer interest into operational readiness.</p><div class="grid-3 section"><article class="card"><h3>Owner-operators</h3><p>Start with an affordable entry point that makes intake, bid posture, and next actions more professional.</p></article><article class="card"><h3>Growing teams</h3><p>Expand into stronger coordination across proposals, customer communication, and structured rollout.</p></article><article class="card"><h3>Enterprise-minded contractors</h3><p>Position FCA as a broader system for commercial continuity, communications, and Auricrux-guided scaling.</p></article></div></div></main>'

create_page "/pricing" "FCA Pricing" '
<main class="hero-simple"><div class="wrap"><div class="kicker"><b>Commercial</b> Pricing</div><h1>Pricing built to give contractors a clear entry path and a visible expansion ladder.</h1><p class="lead">The public pricing surface now includes low-tier, mid-tier, growth, and enterprise options so buyers can see a credible path from first adoption through broader rollout.</p><div class="grid-5 section"><article class="card plan-card"><div class="eyebrow">Entry</div><h3>Startup Workspace</h3><div class="price">$99/mo</div><p>For owner-operators and very small contractors needing branded intake, bid continuity, and Auricrux-guided next actions.</p><ul class="feature-list"><li>Light commercial entry point</li><li>Bid intake positioning</li><li>Auricrux guidance layer</li></ul><div class="cta-row"><a class="btn btn-primary" href="/intake/?plan=startup">Start Intake</a></div></article><article class="card plan-card"><div class="eyebrow">Low / Mid</div><h3>Team Workspace</h3><div class="price">$499/mo</div><p>For small active teams that need stronger coordination across sales, bids, customer communication, and next-step visibility.</p><ul class="feature-list"><li>Team-level commercial coordination</li><li>Stronger proposal movement</li><li>Broader customer follow-through</li></ul><div class="cta-row"><a class="btn btn-primary" href="/intake/?plan=team">Choose Team</a></div></article><article class="card plan-card"><div class="eyebrow">Launch</div><h3>Pilot Workspace</h3><div class="price">$2,500 one-time</div><p>For guided rollout and first operational deployment with stronger setup, clearer workflow framing, and onboarding support.</p><ul class="feature-list"><li>Guided implementation</li><li>Commercial-to-operational launch</li><li>Onboarding support</li></ul><div class="cta-row"><a class="btn btn-primary" href="/intake/?plan=pilot">Start Pilot Intake</a></div></article><article class="card plan-card"><div class="eyebrow">Growth</div><h3>Growth Platform</h3><div class="price">$1,500/mo</div><p>For contractors scaling customer coordination, communications coverage, billing posture, and broader system continuity.</p><ul class="feature-list"><li>Broader multi-team coordination</li><li>Communications expansion</li><li>Stronger rollout posture</li></ul><div class="cta-row"><a class="btn btn-primary" href="/intake/?plan=growth">Plan Growth Rollout</a></div></article><article class="card plan-card"><div class="eyebrow">Enterprise</div><h3>Enterprise Rollout</h3><div class="price">$3,500+/mo</div><p>For larger organizations adopting FCA as a broader operating system across commercial, operational, training, and Auricrux-guided execution layers.</p><ul class="feature-list"><li>Enterprise rollout planning</li><li>Broader communications lanes</li><li>Executive Auricrux positioning</li></ul><div class="cta-row"><a class="btn btn-primary" href="/intake/?plan=enterprise">Request Enterprise Activation</a></div></article></div></div></main>'

create_page "/about" "About FCA" '
<main class="hero-simple"><div class="wrap"><div class="kicker"><b>Company</b> About</div><h1>Future Contractors of America is building a contractor operating system meant to read like one continuous business flow.</h1><p class="lead">FCA is positioned as a more complete alternative to a fragmented stack of intake forms, spreadsheets, email threads, quote documents, and disconnected handoff tools.</p><div class="grid-2 section"><article class="card"><h3>Why FCA exists</h3><p>Contractors lose time and revenue when customer intake, estimate coordination, proposal movement, and next-step visibility are scattered. FCA is marketed as a system that makes those stages feel connected and easier to grow from.</p></article><article class="card"><h3>Why Auricrux matters</h3><p>Auricrux is the visible intelligence layer that helps explain product fit, compare offers, and direct customers and teams toward the next correct action.</p></article></div></div></main>'

create_page "/contact" "Contact FCA" '
<main class="hero-simple"><div class="wrap"><div class="kicker"><b>Company</b> Contact</div><h1>Talk to FCA about package fit, rollout posture, and activation.</h1><p class="lead">The contact page stays purely commercial before gated access. It is designed to move a buyer toward the best next step: pricing, intake, or direct activation conversation.</p><div class="grid-2 section"><article class="card"><h3>Best next actions</h3><p>If you know what package fits, go straight to intake. If you still need positioning help, compare packages first or ask Auricrux to recommend the right path.</p><div class="right-actions"><a class="btn btn-primary" href="/intake/">Start Intake</a><a class="btn btn-secondary" href="/pricing/">View Pricing</a></div></article><article class="card"><h3>Direct commercial contact</h3><p>Use direct email to discuss low-tier, pilot, growth, or enterprise fit.</p><p><span class="code">hello@futurecontractorsofamerica.com</span></p></article></div></div></main>'

create_page "/auricrux" "Meet Auricrux" '
<main class="hero-simple"><div class="wrap"><div class="badge-gold">Auricrux · Gold command layer</div><h1>Ask Auricrux about FCA, pricing, fit, outcomes, and the best next step.</h1><p class="lead">This public Auricrux surface stays in sales-and-marketing mode before login. It is intended to sound more like a useful product guide and less like an explanation of internal implementation rules.</p><div class="grid-2 section"><section class="card"><div class="logo-strip" style="margin-top:0"><div class="logo-mark auricrux-mark"><div style="width:42px;height:42px;border-radius:12px;background:linear-gradient(135deg,#7C5313 0%,#D49A22 100%);display:flex;align-items:center;justify-content:center;font-weight:900;color:#fff">A</div><div><strong class="gold">Auricrux</strong><div class="small">Sales, fit, and next-step guidance</div></div></div></div><p style="margin-top:16px">Use the prompts below or ask directly about package fit, who FCA is for, expected outcomes, enterprise rollout, or what to do next.</p><div class="grid-2" style="margin-top:16px"><button class="dropbtn" onclick="runPreset(`What is FCA Contractor Command?`)">What is FCA Contractor Command?</button><button class="dropbtn" onclick="runPreset(`Which FCA package fits a small contractor?`)">Which package fits a small contractor?</button><button class="dropbtn" onclick="runPreset(`What is the difference between Team and Growth?`)">Team vs Growth</button><button class="dropbtn" onclick="runPreset(`When should I choose Enterprise Rollout?`)">When choose Enterprise?</button><button class="dropbtn" onclick="runPreset(`What happens after intake?`)">What happens after intake?</button><button class="dropbtn" onclick="runPreset(`Can FCA help me win and convert more work?`)">Can FCA help me win work?</button></div><input id="commandInput" class="field" style="margin-top:16px;padding:12px 13px;border-radius:12px;border:1px solid #355075;background:#07111e;color:#fff;width:100%" placeholder="Ask Auricrux a sales or product question..." /><div class="cta-row"><button class="btn btn-primary" onclick="runCommand()">Send command</button><a class="btn btn-secondary" href="/intake/">Start Intake</a><a class="btn btn-secondary" href="/pricing/">View Pricing</a></div><div id="output" class="output">Auricrux ready. Ask about packages, rollout, expected outcomes, enterprise fit, or the next commercial step.</div></section><aside class="card"><h2>What Auricrux should do here</h2><p class="marketing-note">On the public surface, Auricrux should sound like a strong product guide: explain value, compare tiers, clarify outcomes, and direct the buyer into pricing, intake, activation, contact, or login.</p><div class="list"><div class="row"><span class="dot"></span><div><strong>Explain value</strong><p>Describe what FCA helps contractors improve commercially and operationally.</p></div></div><div class="row"><span class="dot"></span><div><strong>Compare packages</strong><p>Recommend the best tier for the buyer’s current stage and size.</p></div></div><div class="row"><span class="dot"></span><div><strong>Route next steps</strong><p>Send the buyer into intake, pricing, activation, contact, or login as appropriate.</p></div></div></div></aside></div></div></main>
<script>
function reply(text){const q=(text||"").toLowerCase();
 if(q.includes("small contractor")||q.includes("startup")) return "Auricrux: For a very small contractor or owner-operator, Startup Workspace is the cleanest entry point. It gives you a low monthly step into guided intake, bid continuity, and a more professional commercial flow without overcommitting too early.";
 if(q.includes("team")&&q.includes("growth")) return "Auricrux: Team Workspace fits a smaller active crew that needs stronger coordination and customer follow-through at a lower monthly step. Growth Platform is for contractors who are scaling and need broader communications coverage, more structured rollout posture, and a stronger expansion path.";
 if(q.includes("enterprise")) return "Auricrux: Enterprise Rollout is the right fit when FCA needs to support multiple teams, broader communications lanes, more executive visibility, and a bigger rollout motion than a standard growth package can comfortably carry.";
 if(q.includes("win work")||q.includes("convert more work")) return "Auricrux: Yes. FCA is positioned to help contractors win and convert more work by making intake cleaner, bid posture more visible, proposal follow-through stronger, and the handoff into setup less fragmented.";
 if(q.includes("after intake")) return "Auricrux: After intake, FCA clarifies fit, routes the opportunity into the right package and activation posture, and carries the customer toward bid, proposal, and setup continuity instead of letting the commercial path go cold.";
 if(q.includes("what is fca")||q.includes("contractor command")) return "Auricrux: FCA Contractor Command is the contractor growth and execution system for intake, qualification, bid continuity, proposals, award handoff, and the first operational setup path. It is sold as one cleaner system instead of a stack of disconnected front-end tools.";
 if(q.includes("pricing")||q.includes("package")||q.includes("fit")) return "Auricrux: FCA currently presents Startup Workspace at $99 per month, Team Workspace at $499 per month, Pilot Workspace at $2,500 one-time, Growth Platform at $1,500 per month, and Enterprise Rollout at $3,500+ per month.";
 if(q.includes("login")) return "Auricrux: Login begins credential-gated access. If you are still evaluating FCA, the strongest public next steps are pricing, intake, or activation. If you are ready to enter the gated layer, use the published customer credentials on the login page.";
 return "Auricrux: FCA is built to give contractors a cleaner revenue path from first inquiry through proposal and early setup. I can help you compare packages, explain outcomes, and point you to the best next step right now.";}
function runPreset(text){document.getElementById("commandInput").value=text;runCommand();}
function runCommand(){const input=document.getElementById("commandInput");document.getElementById("output").textContent=reply(input.value.trim());}
document.getElementById("commandInput").addEventListener("keydown",function(e){if(e.key==="Enter"){runCommand();}})
</script>'

create_page "/intake" "FCA Intake" '
<main class="hero-simple"><div class="wrap"><div class="kicker"><b>Get Started</b> Intake</div><h1>Start the FCA customer intake flow.</h1><p class="lead">This page is public-facing and commercial by design. It captures your package choice and onboarding intent before you move into activation and gated product access.</p><section class="card section"><form id="intakeForm"><div class="form-grid"><div class="field"><label for="plan">Offer</label><select id="plan"><option value="startup">Startup Workspace</option><option value="team">Team Workspace</option><option value="pilot">Pilot Workspace</option><option value="growth">Growth Platform</option><option value="enterprise">Enterprise Rollout</option></select></div><div class="field"><label for="company">Company</label><input id="company" required placeholder="Your company name" /></div><div class="field"><label for="name">Contact name</label><input id="name" required placeholder="Primary contact" /></div><div class="field"><label for="email">Work email</label><input id="email" type="email" required placeholder="name@company.com" /></div><div class="field"><label for="phone">Phone</label><input id="phone" placeholder="Phone number" /></div><div class="field"><label for="size">Company size</label><select id="size"><option>Owner-operator</option><option>2-5 employees</option><option>6-15 employees</option><option>16-50 employees</option><option>50+ employees</option></select></div><div class="field full"><label for="need">Primary need</label><select id="need"><option>Lead intake and bid continuity</option><option>Proposal and award handoff</option><option>Customer coordination and visibility</option><option>Operational rollout with Auricrux support</option><option>Enterprise operating-system rollout</option></select></div><div class="field full"><label for="notes">What do you need FCA to solve first?</label><textarea id="notes" placeholder="Describe the sales, estimating, proposal, communication, or rollout problem you want FCA to solve first."></textarea></div></div><div class="cta-row"><button class="btn btn-primary" type="submit">Continue to activation</button><a class="btn btn-secondary" href="/pricing/">Back to pricing</a></div><div class="status">Commercial flow: choose package → complete intake → apply activation code if needed → move into gated access.</div></form></section></div></main>
<script>const params=new URLSearchParams(window.location.search);const preset=params.get("plan");if(preset){document.getElementById("plan").value=preset;}document.getElementById("intakeForm").addEventListener("submit",function(e){e.preventDefault();const plan=document.getElementById("plan").value;const company=encodeURIComponent(document.getElementById("company").value);window.location.href="/checkout/?plan="+encodeURIComponent(plan)+"&company="+company;});</script>'

create_page "/checkout" "FCA Checkout & Activation" '
<main class="hero-simple"><div class="wrap"><div class="kicker"><b>Get Started</b> Activation</div><h1>Move from interest into package activation.</h1><p class="lead">This page stays commercial and public-facing. It gives you a package summary, activation guidance, and a free-code option for zero-dollar founder activation without claiming a fully automated live billing stack.</p><section class="card section"><div class="status">Truthful commercial boundary: package activation is public-facing here; the actual protected product layer begins after login.</div><h2 id="offerTitle" style="margin-top:18px">Selected offer</h2><p id="summary"></p><div class="field" style="margin-top:16px"><label for="promo">Activation code</label><input id="promo" placeholder="Enter activation code if you have one" /></div><div class="cta-row"><button class="btn btn-primary" type="button" onclick="applyCode()">Apply code</button><a class="btn btn-secondary" href="mailto:hello@futurecontractorsofamerica.com?subject=FCA%20Package%20Activation">Request manual activation</a><a class="btn btn-secondary" href="/login/">Go to login</a></div><div id="promoStatus" class="status" style="margin-top:14px">Founder free-code path: use <span class="code">FCA-FOUNDER-FREE-2026</span> to zero the current package for validation/onboarding.</div></section></div></main>
<script>const params=new URLSearchParams(window.location.search);const plan=params.get("plan")||"startup";const company=decodeURIComponent(params.get("company")||"your company");const titleMap={startup:"Startup Workspace",team:"Team Workspace",pilot:"Pilot Workspace",growth:"Growth Platform",enterprise:"Enterprise Rollout"};const priceMap={startup:"$99/mo",team:"$499/mo",pilot:"$2,500 one-time",growth:"$1,500/mo",enterprise:"$3,500+/mo"};document.getElementById("offerTitle").textContent=(titleMap[plan]||"FCA Package")+" · "+(priceMap[plan]||"pricing pending");document.getElementById("summary").textContent="Selected for "+company+". Next action: apply a founder activation code or request manual activation, then move into the gated access layer.";function applyCode(){const val=(document.getElementById("promo").value||"").trim();const box=document.getElementById("promoStatus");if(val==="FCA-FOUNDER-FREE-2026"){box.className="status success";box.textContent="Founder activation code accepted. Your current onboarding path is cleared as a no-charge activation route. Next step: go to login and use the real customer credentials published there.";}else{box.className="status error";box.textContent="Code not recognized. Use the founder code exactly as issued or request manual activation.";}}</script>'

create_page "/login" "FCA Login" '
<main class="hero-simple"><div class="wrap"><div class="kicker"><b>Access</b> Login</div><h1>Credential-gated access begins here.</h1><p class="lead">You asked for real customer credentials. The launch customer credentials below are now the primary customer-facing validation credentials for the current gated layer.</p><div class="grid-2 section"><article class="card"><h2>Current customer credentials</h2><div class="list"><div class="row"><span class="dot"></span><div><strong>Primary customer credential</strong><p>Email: <span class="code">launch.customer@futurecontractorsofamerica.com</span><br/>Password: <span class="code">FCA-Launch-2026!</span></p></div></div><div class="row"><span class="dot"></span><div><strong>Secondary founder validation credential</strong><p>Email: <span class="code">founder.test@futurecontractorsofamerica.com</span><br/>Password: <span class="code">FCA-HandsOff-2026!</span></p></div></div></div><p class="small">Recommended path for you now: use the launch customer credential as the active customer login. If backend validation is degraded, the page still accepts these credentials locally to avoid blocking access checks.</p></article><aside class="card"><h2>Sign in</h2><form id="loginForm"><div class="field"><label for="email">Work email</label><input id="email" type="email" placeholder="name@company.com" value="launch.customer@futurecontractorsofamerica.com" /></div><div class="field"><label for="password">Password</label><input id="password" type="password" placeholder="Enter your password" value="FCA-Launch-2026!" /></div><div class="cta-row"><button class="btn btn-primary" type="submit" id="signInBtn">Sign in</button></div><div id="statusBox" class="status">Login validates the current customer credentials and then routes into the current gated validation surface.</div></form></aside></div></div></main>
<script>
const KNOWN=[{email:"founder.test@futurecontractorsofamerica.com",password:"FCA-HandsOff-2026!"},{email:"launch.customer@futurecontractorsofamerica.com",password:"FCA-Launch-2026!"}];
const form=document.getElementById("loginForm");const email=document.getElementById("email");const password=document.getElementById("password");const box=document.getElementById("statusBox");const btn=document.getElementById("signInBtn");
function setStatus(msg,kind){box.textContent=msg;box.className="status"+(kind?" "+kind:"");}
function matchLocal(e,p){const em=(e||"").trim().toLowerCase();const pw=(p||"").trim();return KNOWN.some(x=>x.email.toLowerCase()===em&&x.password===pw);}
async function authenticate(payload){try{const response=await fetch('/api/customer-login',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)});const data=await response.json().catch(()=>({ok:false}));if(response.ok&&data.ok){return true;}}catch(e){} return matchLocal(payload.email,payload.password);}
form.addEventListener("submit",async function(e){e.preventDefault();btn.disabled=true;setStatus("Authenticating credentials…");const ok=await authenticate({email:email.value,password:password.value});if(ok){setStatus("Login successful. Opening the current gated customer surface…","success");setTimeout(()=>window.location.href='/fca-customer-status/',400);}else{setStatus("Credentials did not validate. Use the published customer credentials exactly as shown.","error");}btn.disabled=false;});
</script>'

